// Traduce un landmark_key a coordenadas usando el diccionario inline.
// Si vienen lat/lng directos, los usa. Si vienen ambos, prioriza landmark_key.
//
// Output: { lat, lng, radius_km, query, filters }

const LANDMARKS = {
  // BAHIA BLANCA
  'centro_bb': { lat: -38.7191, lng: -62.2724, radius_km: 1.0 },
  'uns': { lat: -38.6996, lng: -62.2649, radius_km: 0.8 },
  'shopping_bahia_plaza': { lat: -38.7167, lng: -62.2540, radius_km: 0.7 },
  'hospital_penna': { lat: -38.7188, lng: -62.2670, radius_km: 0.6 },
  'hospital_italiano': { lat: -38.7163, lng: -62.2666, radius_km: 0.6 },
  'teatro_municipal': { lat: -38.7150, lng: -62.2683, radius_km: 0.5 },
  'parque_de_mayo': { lat: -38.7325, lng: -62.2615, radius_km: 1.0 },
  'palihue': { lat: -38.7398, lng: -62.2552, radius_km: 1.2 },
  'villa_mitre': { lat: -38.7136, lng: -62.2845, radius_km: 1.0 },
  'villa_belgrano': { lat: -38.7233, lng: -62.2785, radius_km: 1.0 },
  'patagonia': { lat: -38.7000, lng: -62.3000, radius_km: 1.0 },
  'estacion_sud': { lat: -38.7331, lng: -62.2740, radius_km: 0.6 },
  'hipodromo': { lat: -38.7081, lng: -62.3007, radius_km: 0.8 },
  'ingeniero_white_puerto': { lat: -38.7806, lng: -62.2664, radius_km: 1.5 },
  // MONTE HERMOSO
  'centro_mh': { lat: -38.9881, lng: -61.2970, radius_km: 1.5 },
  'costanera_mh': { lat: -38.9881, lng: -61.2970, radius_km: 2.5 },
  'las_dunas_complejo': { lat: -38.9796, lng: -61.3257, radius_km: 1.5 },
  'la_olla': { lat: -38.9800, lng: -61.3400, radius_km: 3.0 },
  'camping_americano': { lat: -38.9810, lng: -61.3300, radius_km: 2.5 },
  'faro_recalada': { lat: -38.9881, lng: -61.2970, radius_km: 2.0 },
  'sauce_grande': { lat: -38.9803, lng: -61.1500, radius_km: 3.0 },
  'monte_del_este': { lat: -38.9810, lng: -61.2580, radius_km: 2.0 },
  'punto_blanco': { lat: -38.9881, lng: -61.2970, radius_km: 1.5 },
  // PUNTA ALTA
  'centro_pa': { lat: -38.8775, lng: -62.0731, radius_km: 1.0 },
  'base_naval': { lat: -38.8956, lng: -62.0894, radius_km: 1.0 },
  // PEHUEN CO
  'pehuen_co': { lat: -38.9979, lng: -61.5454, radius_km: 1.5 },
  // SIERRAS
  'sierra_de_la_ventana': { lat: -38.1500, lng: -61.7964, radius_km: 2.0 },
  'tornquist': { lat: -38.0976, lng: -62.2236, radius_km: 1.5 },
  'villa_ventana': { lat: -38.0700, lng: -61.8200, radius_km: 1.5 },
  // VILLARINO
  'medanos_villarino': { lat: -38.8267, lng: -62.6914, radius_km: 2.0 },
  'pedro_luro': { lat: -39.4889, lng: -62.6797, radius_km: 1.5 },
  'cabildo': { lat: -38.4900, lng: -61.8736, radius_km: 1.5 },
};

const inp = $input.first().json || {};

let lat, lng, radius_km;

// 1) Si vino landmark_key, usar ese
if (inp.landmark_key && LANDMARKS[inp.landmark_key]) {
  const lm = LANDMARKS[inp.landmark_key];
  lat = lm.lat; lng = lm.lng;
  radius_km = Number(inp.radius_km) > 0 ? Number(inp.radius_km) : lm.radius_km;
}
// 2) Si vinieron lat/lng directos
else if (Number(inp.lat) && Number(inp.lng)) {
  lat = Number(inp.lat); lng = Number(inp.lng);
  radius_km = Number(inp.radius_km) > 0 ? Number(inp.radius_km) : 2.0;
}
// 3) Error
else {
  return [{ json: { error: 'Debe pasar landmark_key conocido o lat+lng directos. Landmarks: ' + Object.keys(LANDMARKS).join(', ') } }];
}

// Filtros opcionales
const filters = {};
if (inp.operation === 'sale' || inp.operation === 'rent') filters.operation = inp.operation;
if (inp.property_type) filters.property_type = String(inp.property_type);
if (Number(inp.price_max) > 0) filters.price_max = Number(inp.price_max);

return [{
  json: {
    lat, lng, radius_km,
    query: inp.query ? String(inp.query) : undefined,
    filters,
    limit: 5,
  }
}];

// Formatear respuesta del RAG para el agente CORE.
// Devuelve string con las props encontradas + sus distancias.

const inp = $input.first().json || {};
const orig = $('Resolve Landmark → Coords').first().json;

if (inp.error) {
  return [{ json: { result: 'ERROR_GEO: ' + (inp.error || '').slice(0, 200) } }];
}

if (!inp.items || inp.items.length === 0) {
  return [{ json: { result: 'SIN_PROPIEDADES_GEO | centro=(' + orig.lat + ',' + orig.lng + ') radio=' + orig.radius_km + 'km. Probar con radio mayor o text search clasico.' } }];
}

const lines = inp.items.map((p, i) => {
  const precio = p.price ? p.price + ' ' + (p.price_currency || '') : (p.price_text || 'Consultar');
  const ubic = (p.barrio && p.barrio !== 'unknown') ? p.barrio : (p.zona || 'Bahia Blanca');
  return (i+1) + '. [' + p.prop_id + '] ' + (p.title || '?')
    + ' | ' + (p.property_type || '?')
    + ' | ' + ubic
    + ' | ' + (p.bedrooms ? p.bedrooms + ' amb' : 'amb ?')
    + ' | ' + (p.area_m2 ? p.area_m2 + ' m2' : 'm2 ?')
    + ' | ' + precio
    + ' | a ' + (p.dist_km !== null ? p.dist_km.toFixed(2) + ' km' : '? km')
    + ' | URL: ' + p.url;
});

const header = 'PROPIEDADES_CERCANAS (' + inp.items.length + ', centro=' + orig.lat.toFixed(4) + ',' + orig.lng.toFixed(4) + ', radio=' + orig.radius_km + 'km):';

return [{ json: { result: header + '\n' + lines.join('\n') } }];
